JSON config merger utility for deep merging and validation.
"""

from typing import Any, List, Dict


def merge_configs(*configs: Dict[str, Any]) -> Dict[str, Any]:
    """
    Deep merge multiple config dictionaries.

    Rules:
    - Nested dicts merge recursively
    - Lists concatenate (later values append to earlier)
    - Later values override earlier for scalar keys

    Args:
        *configs: Variable number of config dictionaries to merge

    Returns:
        A new merged dictionary

    Example:
        >>> merge_configs({'a': 1, 'b': {'x': 10}}, {'b': {'y': 20}, 'c': 2})
        {'a': 1, 'b': {'x': 10, 'y': 20}, 'c': 2}
    """
    result = {}

    for config in configs:
        if not isinstance(config, dict):
            raise TypeError(f"Expected dict, got {type(config).__name__}")

        for key, value in config.items():
            if key in result:
                existing_value = result[key]
                # If both are dicts, merge recursively
                if isinstance(existing_value, dict) and isinstance(value, dict):
                    result[key] = merge_configs(existing_value, value)
                # If both are lists, concatenate
                elif isinstance(existing_value, list) and isinstance(value, list):
                    result[key] = existing_value + value
                # Otherwise, later value overrides
                else:
                    result[key] = value
            else:
                # Deep copy for nested structures
                if isinstance(value, dict):
                    result[key] = merge_configs(value)
                elif isinstance(value, list):
                    result[key] = list(value)
                else:
                    result[key] = value

    return result


def validate_merge(*configs: Dict[str, Any]) -> List[str]:
    """
    Detect type conflicts across multiple config dictionaries.

    Args:
        *configs: Variable number of config dictionaries to validate

    Returns:
        List of conflict descriptions. Empty list means no conflicts.

    Example:
        >>> validate_merge({'a': 1}, {'a': 'string'})
        ['Key "a" has conflicting types: int vs str']
    """
    conflicts = []

    # Build a mapping of key to type information
    key_types: Dict[str, List[type]] = {}

    for config in configs:
        if not isinstance(config, dict):
            conflicts.append(f"Invalid config type: expected dict, got {type(config).__name__}")
            continue

        for key, value in config.items():
            if key not in key_types:
                key_types[key] = [type(value)]
            else:
                key_types[key].append(type(value))

    # Check for conflicts
    for key, types in key_types.items():
        if len(set(types)) > 1:
            type_names = [t.__name__ for t in types]
            conflicts.append(f'Key "{key}" has conflicting types: {", ".join(type_names)}')

    return conflicts
