{"path":"tmp/eval36_test.py","content":""""
Tests for the JSON config merger utility.
"""

import sys
import os

# Add parent directory to path to import the merger module
sys.path.insert(0, os.path.dirname(os.path.dirname(os.path.abspath(__file__))))

from eval36_merger import merge_configs, validate_merge


def test_basic_shallow_merge():
    """Test basic shallow merge of two flat dicts."""
    config1 = {'a': 1, 'b': 2}
    config2 = {'b': 3, 'c': 4}
    result = merge_configs(config1, config2)

    assert result == {'a': 1, 'b': 3, 'c': 4}, f"Expected {{'a': 1, 'b': 3, 'c': 4}}, got {result}"
    print("✓ test_basic_shallow_merge passed")


def test_deep_nested_merge():
    """Test deep nested merge (3 levels)."""
    config1 = {'a': {'b': {'c': 1}}}
    config2 = {'a': {'b': {'d': 2, 'e': {'f': 3}}}}
    result = merge_configs(config1, config2)

    expected = {'a': {'b': {'c': 1, 'd': 2, 'e': {'f': 3}}}}
    assert result == expected, f"Expected {expected}, got {result}"
    print("✓ test_deep_nested_merge passed")


def test_list_concatenation():
    """Test list concatenation."""
    config1 = {'items': [1, 2]}
    config2 = {'items': [3, 4]}
    result = merge_configs(config1, config2)

    assert result == {'items': [1, 2, 3, 4]}, f"Expected {{'items': [1, 2, 3, 4]}}, got {result}"
    print("✓ test_list_concatenation passed")


def test_override_precedence():
    """Test that later configs override earlier ones."""
    config1 = {'a': 1, 'b': 2, 'c': {'x': 10, 'y': 20}}
    config2 = {'b': 3, 'c': {'x': 100}}
    config3 = {'a': 10, 'c': {'y': 200, 'z': 300}}

    result = merge_configs(config1, config2, config3)

    expected = {'a': 10, 'b': 3, 'c': {'x': 100, 'y': 200, 'z': 300}}
    assert result == expected, f"Expected {expected}, got {result}"
    print("✓ test_override_precedence passed")


def test_type_conflict_detection():
    """Test detection of type conflicts."""
    config1 = {'a': 1}
    config2 = {'a': 'string'}
    config3 = {'a': {'nested': 'dict'}}

    conflicts = validate_merge(config1, config2, config3)

    expected_conflicts = [
        'Key "a" has conflicting types: int, str, dict'
    ]
    assert conflicts == expected_conflicts, f"Expected {expected_conflicts}, got {conflicts}"
    print("✓ test_type_conflict_detection passed")


def test_empty_input_handling():
    """Test handling of empty inputs."""
    # Empty list of configs
    result = merge_configs()
    assert result == {}, f"Expected empty dict, got {result}"

    # Empty dicts
    result = merge_configs({}, {})
    assert result == {}, f"Expected empty dict, got {result}"

    # Mixed empty and non-empty
    result = merge_configs({}, {'a': 1}, {})
    assert result == {'a': 1}, f"Expected {{'a': 1}}, got {result}"

    # No conflicts with empty inputs
    conflicts = validate_merge()
    assert conflicts == [], f"Expected empty list, got {conflicts}"

    conflicts = validate_merge({}, {})
    assert conflicts == [], f"Expected empty list, got {conflicts}"

    print("✓ test_empty_input_handling passed")


def test_mixed_types_in_merge():
    """Test mixing dict, list, and scalar values."""
    config1 = {
        'string': 'hello',
        'number': 42,
        'bool': True,
        'list': [1, 2],
        'nested': {'a': 1, 'b': 2}
    }
    config2 = {
        'string': 'world',
        'number': 100,
        'bool': False,
        'list': [3, 4],
        'nested': {'b': 20, 'c': 30}
    }

    result = merge_configs(config1, config2)

    expected = {
        'string': 'world',
        'number': 100,
        'bool': False,
        'list': [1, 2, 3, 4],
        'nested': {'a': 1, 'b': 20, 'c': 30}
    }
    assert result == expected, f"Expected {expected}, got {result}"
    print("✓ test_mixed_types_in_merge passed")


def test_list_with_dicts():
    """Test merging lists containing dicts."""
    config1 = {'items': [{'id': 1, 'name': 'a'}, {'id': 2, 'name': 'b'}]}
    config2 = {'items': [{'id': 3, 'name': 'c'}, {'id': 4, 'name': 'd'}]}

    result = merge_configs(config1, config2)

    expected = {
        'items': [
            {'id': 1, 'name': 'a'},
            {'id': 2, 'name': 'b'},
            {'id': 3, 'name': 'c'},
            {'id': 4, 'name': 'd'}
        ]
    }
    assert result == expected, f"Expected {expected}, got {result}"
    print("✓ test_list_with_dicts passed")


def test_non_dict_input_error():
    """Test that non-dict inputs raise TypeError."""
    try:
        merge_configs({'a': 1}, 'not a dict')
        assert False, "Should have raised TypeError"
    except TypeError as e:
        assert "Expected dict" in str(e)
        print("✓ test_non_dict_input_error passed")


if __name__ == '__main__':
    print("Running tests for eval36_merger...\n")

    test_basic_shallow_merge()
    test_deep_nested_merge()
    test_list_concatenation()
    test_override_precedence()
    test_type_conflict_detection()
    test_empty_input_handling()
    test_mixed_types_in_merge()
    test_list_with_dicts()
    test_non_dict_input_error()

    print("\n" + "="*50)
    print("ALL TESTS PASSED!")
    print("="*50)
